#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    int x,ans=0;
    cin>>x;
    cin>>s;
    for(int i=0;i<s.size();i++){
        int tmp;
        if(s[i]>='0' && s[i]<='9')tmp=s[i]-'0';
        else tmp=s[i]-'A'+10;
        ans+=tmp*pow(x,s.size()-i-1);
    }
    cout<<ans;
    return 0;
}
